// solve calculates the frequency of given queries as maximal words in the concatenated string s.
func solve(chunks []string, queries []string) []int64 {
	// 1. Concatenate chunks to form s
	s := strings.Join(chunks, "")
	N := len(s)

	// Map to store counts of maximal valid words
	wordCounts := make(map[string]int64)

	// Helper function to check if a rune is a lowercase English letter
	isLetter := func(r rune) bool {
		return r >= 'a' && r <= 'z'
	}

	// 2. Parse s to find and count maximal words
	currentWord := []rune{}
	inWord := false

	for i, r := range s {
		char := byte(r)

		if isLetter(r) {
			// Case 1: Current character is a letter
			if !inWord {
				// Start of a new word
				inWord = true
				currentWord = []rune{r}
			} else {
				// Continuation of the current word
				currentWord = append(currentWord, r)
			}
		} else if char == '-' {
			// Case 2: Current character is a hyphen

			// Check if it's a legal internal hyphen: surrounded by letters
			isLegalHyphen := false
			if i > 0 && i < N-1 {
				prevChar := s[i-1]
				nextChar := s[i+1]
				if isLetter(rune(prevChar)) && isLetter(rune(nextChar)) {
					isLegalHyphen = true
				}
			}

			if isLegalHyphen {
				if inWord {
					// Hyphen extends the word
					currentWord = append(currentWord, r)
				}
				// If not inWord, this hyphen is isolated by delimiters/boundaries, acts as separator
			} else {
				// Illegal hyphen or boundary hyphen -> acts as delimiter
				if inWord {
					// Word ended right before this illegal hyphen
					wordStr := string(currentWord)
					wordCounts[wordStr]++
					currentWord = nil
					inWord = false
				}
				// If not in word, state remains not in word
			}
		} else {
			// Case 3: Current character is any other delimiter (space, punctuation, etc.)
			if inWord {
				// Word ended before this delimiter
				wordStr := string(currentWord)
				wordCounts[wordStr]++
				currentWord = nil
				inWord = false
			}
			// If not in word, state remains not in word
		}
	}

	// Handle the last word if the string ended while processing a word
	if inWord && len(currentWord) > 0 {
		wordStr := string(currentWord)
		wordCounts[wordStr]++
	}

	// 3. Process queries
	results := make([]int64, len(queries))
	for i, q := range queries {
		// Since the problem guarantees queries[i] is an effective word, 
		// we just look up the count. If it somehow isn't found (shouldn't happen based on prompt), count is 0.
		results[i] = wordCounts[q]
	}

	return results
}
